function requiredText(value, field) {
  if (typeof value !== 'string' || value.length === 0) {
    throw new TypeError(`${field} must be a non-empty string`);
  }
  return value;
}

export function normalizeObservation(input) {
  if (!input || typeof input !== 'object') {
    throw new TypeError('observation must be an object');
  }

  const value = Number(input.value);
  if (!Number.isFinite(value)) {
    throw new TypeError('observation value must be numeric or null');
  }

  return {
    sensorId: requiredText(input.sensorId, 'sensorId'),
    metric: requiredText(input.metric, 'metric'),
    value,
    unit: input.unit == null ? null : String(input.unit)
  };
}

