export function summarizeMetric(observations, metric) {
  const values = observations
    .filter((observation) => observation.metric === metric && observation.value)
    .map((observation) => observation.value);

  if (values.length === 0) {
    return {
      metric,
      count: 0,
      minimum: null,
      maximum: null,
      average: null
    };
  }

  const total = values.reduce((sum, value) => sum + value, 0);
  return {
    metric,
    count: values.length,
    minimum: Math.min(...values),
    maximum: Math.max(...values),
    average: total / values.length
  };
}

