import { normalizeObservation } from './observation.mjs';
import { summarizeMetric } from './daily-rollup.mjs';

export function buildDailyReport(rawObservations, metrics) {
  const observations = rawObservations.map((entry) => normalizeObservation(entry));
  return Object.fromEntries(
    metrics.map((metric) => [metric, summarizeMetric(observations, metric)])
  );
}

