import test from 'node:test';
import assert from 'node:assert/strict';

import { normalizeObservation } from '../src/observation.mjs';
import { summarizeMetric } from '../src/daily-rollup.mjs';
import { buildDailyReport } from '../src/report-service.mjs';

test('numeric strings from a sensor are normalized', () => {
  assert.deepEqual(
    normalizeObservation({
      sensorId: 'ahu-1',
      metric: 'temperature',
      value: '21.5',
      unit: 'C'
    }),
    {
      sensorId: 'ahu-1',
      metric: 'temperature',
      value: 21.5,
      unit: 'C'
    }
  );
});

test('positive observations produce daily statistics', () => {
  assert.deepEqual(
    summarizeMetric(
      [
        { sensorId: 'ahu-1', metric: 'temperature', value: 20 },
        { sensorId: 'ahu-2', metric: 'temperature', value: 24 },
        { sensorId: 'ahu-1', metric: 'humidity', value: 40 }
      ],
      'temperature'
    ),
    {
      metric: 'temperature',
      count: 2,
      minimum: 20,
      maximum: 24,
      average: 22
    }
  );
});

test('the report service builds summaries for requested metrics', () => {
  const report = buildDailyReport(
    [
      { sensorId: 'room-1', metric: 'co2', value: 600, unit: 'ppm' },
      { sensorId: 'room-2', metric: 'co2', value: 800, unit: 'ppm' }
    ],
    ['co2', 'humidity']
  );

  assert.equal(report.co2.average, 700);
  assert.equal(report.humidity.count, 0);
  assert.equal(report.humidity.average, null);
});
